import pathlib
path = pathlib.Path('index.html')
text = path.read_text(encoding='utf-8')
text = text.replace('\r\n', '\n')
old = """var _dbSortCol = 0, _dbSortAsc = true, _dbFilter = '';\nvar _dbEditingKey = null;\n// In-memory overrides for admin edits (toda_key → {col: value})\nvar _dbEdits = {};\ntry { var _de = localStorage.getItem('atl_db_edits'); if(_de) _dbEdits = JSON.parse(_de); } catch(e) {}\n\nfunction saveDbEdits() {\n  try { localStorage.setItem('atl_db_edits', JSON.stringify(_dbEdits)); } catch(e) {}\n}\n"""
new = """var _dbSortCol = 0, _dbSortAsc = true, _dbFilter = '';\nvar _dbEditingKey = null;\nvar _dbCols = loadDbCols();\nvar _dbDeletes = loadDbDeletes();\n// In-memory overrides for admin edits (toda_key → {col: value})\nvar _dbEdits = {};\ntry { var _de = localStorage.getItem('atl_db_edits'); if(_de) _dbEdits = JSON.parse(_de); } catch(e) {}\n\nfunction saveDbEdits() {\n  try { localStorage.setItem('atl_db_edits', JSON.stringify(_dbEdits)); } catch(e) {}\n}\nfunction loadDbCols(){\n  try { var raw = localStorage.getItem('atl_db_columns'); if(raw){ var parsed = JSON.parse(raw); if(Array.isArray(parsed) && parsed.every(function(c){ return c && c.key; })) return parsed; } } catch(e) {}\n  return DB_COLS.slice();\n}\nfunction saveDbCols(){\n  try { localStorage.setItem('atl_db_columns', JSON.stringify(_dbCols)); } catch(e) {}\n}\nfunction loadDbDeletes(){\n  try { var raw = localStorage.getItem('atl_db_deleted'); if(raw){ var parsed = JSON.parse(raw); if(parsed && typeof parsed === 'object') return parsed; } } catch(e) {}\n  return {};\n}\nfunction saveDbDeletes(){\n  try { localStorage.setItem('atl_db_deleted', JSON.stringify(_dbDeletes)); } catch(e) {}\n}\nfunction normalizeDbColumnKey(str){\n  return (str||'').toString().trim().toLowerCase().replace(/[^a-z0-9_]+/g,'_').replace(/^_+|_+$/g,'');\n}\nfunction deleteDbRow(rowKey,rowName){\n  if(!rowKey) return;\n  if(!confirm('Delete row "' + (rowName||rowKey) + '" from the local database view?')) return;\n  _dbDeletes[rowKey] = true;\n  saveDbDeletes();\n  _dbEditingKey = null;\n  renderDb();\n}\nfunction restoreDeletedDbRows(){\n  if(!confirm('Restore all locally deleted rows?')) return;\n  _dbDeletes = {};\n  saveDbDeletes();\n  renderDb();\n}\nfunction addDbColumn(){\n  if(!adminSession) return;\n  var rawKey = prompt('Enter a new column key (letters, numbers, underscore):');\n  if(!rawKey) return;\n  var key = normalizeDbColumnKey(rawKey);\n  if(!key){ alert('Invalid column key.'); return; }\n  if(_dbCols.some(function(c){ return c.key === key; })){ alert('Column key already exists.'); return; }\n  var label = prompt('Enter a display label for this column:', rawKey.trim()) || key;\n  var editable = confirm('Should this column be editable? Click OK for yes, Cancel for no.');\n  _dbCols.push({key:key,label:label,editable:!!editable});\n  saveDbCols();\n  renderDb();\n}\nfunction editDbColumns(){\n  if(!adminSession) return;\n  var list = _dbCols.map(function(c,i){ return (i+1) + '. ' + c.key + ' – ' + c.label + (c.editable ? ' [editable]' : ''); }).join('\n');\n  var choice = prompt('Manage columns:\n' + list + '\n\nEnter a number to edit a column, or type ADD to create a new one, or type REMOVE to delete a custom column.');\n  if(!choice) return;\n  if(choice.toUpperCase() === 'ADD'){ addDbColumn(); return; }\n  if(choice.toUpperCase() === 'REMOVE'){\n    var rem = prompt('Enter the number of the custom column to remove:');\n    var idx = parseInt(rem,10) - 1;\n    if(isNaN(idx) || idx < 0 || idx >= _dbCols.length){ alert('Invalid selection.'); return; }\n    if(!confirm('Remove column "' + _dbCols[idx].label + '"?')) return;\n    _dbCols.splice(idx,1);\n    saveDbCols();\n    renderDb();\n    return;\n  }\n  var idx = parseInt(choice,10) - 1;\n  if(isNaN(idx) || idx < 0 || idx >= _dbCols.length){ alert('Invalid selection.'); return; }\n  var col = _dbCols[idx];\n  var newLabel = prompt('Edit label for ' + col.key + ':', col.label);\n  if(newLabel !== null && newLabel.trim() !== ''){ col.label = newLabel.trim(); }\n  var toggle = confirm('Make this column editable? Click OK for yes, Cancel for no.');\n  col.editable = !!toggle;\n  saveDbCols();\n  renderDb();\n}\n"""
if old not in text:
    raise SystemExit('Old block not found')
text = text.replace(old, new, 1)
old_delete = """  // Apply admin edits on top\n  Object.keys(_dbEdits).forEach(function(key) {\n    if (merged[key]) {\n      Object.assign(merged[key], _dbEdits[key]);\n    }\n  });\n"""
new_delete = """  // Apply admin edits on top\n  Object.keys(_dbDeletes).forEach(function(key){ if(_dbDeletes[key] && merged[key]) delete merged[key]; });\n  Object.keys(_dbEdits).forEach(function(key) {\n    if (merged[key]) {\n      Object.assign(merged[key], _dbEdits[key]);\n    }\n  });\n"""
if old_delete not in text:
    raise SystemExit('Delete insertion point not found')
text = text.replace(old_delete, new_delete, 1)
text = text.replace("    return DB_COLS.some(function(c) { return (r[c.key]||'').toLowerCase().includes(q); });", "    return _dbCols.some(function(c) { return (r[c.key]||'').toLowerCase().includes(q); });", 1)
text = text.replace('  var sk = DB_COLS[_dbSortCol].key;','  if(_dbSortCol >= _dbCols.length) _dbSortCol = 0;\n  var sk = _dbCols[_dbSortCol].key;', 1)
text = text.replace('  DB_COLS.forEach(function(col, ci) {','  _dbCols.forEach(function(col, ci) {', 1)
text = text.replace('  DB_COLS.forEach(function(col) {','  _dbCols.forEach(function(col) {', 1)
text = text.replace('      if (adminSession) {','      if (adminSession) {\n    var adminControls = document.getElementById(\'db-admin-controls\');\n    if(adminControls) adminControls.style.display = adminSession ? \'flex\' : \'none\';', 1)
path.write_text(text.replace('\n','\r\n'), encoding='utf-8')
print('patch part 1 applied')
